import React from 'react';
import './Features.css';

const featureList = [
  {
    title: '24/7 실시간 대화',
    description: '토끼와 고양이 캐릭터가 먼저 말을 걸어주고 지금 감정에 맞는 대화를 이어가요.',
    tone: 'blue',
    motion: 'bounce',
    image: '/images/rabbit-duo.png',
  },
  {
    title: 'AI 감정 분석',
    description: '대화 맥락을 읽고 감정 흐름과 피로 신호를 부드럽게 정리해줘요.',
    tone: 'yellow',
    motion: 'spin',
    image: '/images/rabbit.png',
  },
  {
    title: '완벽한 비밀 보장',
    description: '민감한 이야기일수록 안심하고 털어놓을 수 있게 보호 중심 UX로 설계했어요.',
    tone: 'mint',
    motion: 'wiggle',
    image: '/images/cat.png',
  },
  {
    title: '체크인과 리포트',
    description: '오늘 상태 기록부터 주간 요약까지 같은 캐릭터 흐름으로 이어져요.',
    tone: 'pink',
    motion: 'bounce',
    image: '/images/rabbit-duo.png',
  },
  {
    title: '봇 일기 자동 정리',
    description: '하루의 대화를 한 줄 기록처럼 남겨서 감정 회고를 쉽게 도와줘요.',
    tone: 'purple',
    motion: 'wiggle',
    image: '/images/rabbit.png',
  },
  {
    title: '캐릭터 중심 경험',
    description: '말풍선, 선택지, 입력창까지 모두 캐릭터 중심으로 보여줘요.',
    tone: 'peach',
    motion: 'spin',
    image: '/images/cat.png',
  },
];

export default function Features() {
  return (
    <section className="cutefeatures-section" id="features">
      <div className="cutefeatures-container">
        <div className="cutefeatures-heading">
          <span className="cutefeatures-kicker">마음친구만의 특별함</span>
          <h2>
            기능 설명도 단순 카드가 아니라
            <br />
            <strong>캐릭터와 연결된 경험</strong>
          </h2>
          <p>
            아이콘만 던져두는 방식이 아니라, 토끼와 고양이 캐릭터가
            서비스 전체에서 같은 흐름으로 안내하도록 구성했어요.
          </p>
        </div>

        <div className="cutefeatures-grid">
          {featureList.map((item) => (
            <article
              key={item.title}
              className={`cutefeatures-card cutefeatures-card--${item.tone} motion-${item.motion}`}
            >
              <div className="cutefeatures-thumb">
                <img src={item.image} alt={item.title} />
              </div>

              <div className="cutefeatures-card__body">
                <h3>{item.title}</h3>
                <p>{item.description}</p>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}
